async function bulkInsert(array, db) {
    if (array.length == 0)
        return;
    const chunkSize = 250;
    for (let i = 0; i < array.length; i += chunkSize) {
        const items = array.slice(i, i + chunkSize);
        // do whatever
        const c = db.createCommand();
        let sql = 'insert into ' +
            (await items[0]._.metadata.getDbName()) +
            ' (' +
            (await Promise.all(items[0]._.metadata.fields.toArray().map((f) => f.getDbName()))).join(',') +
            ') values ';
        sql += items
            .map((row) => '(' +
            row.$.toArray()
                .map((f) => c.addParameterAndReturnSqlToken(f.metadata.valueConverter.toDb(f.value)))
                .join(', ') +
            ')')
            .join(',');
        await c.execute(sql);
    }
}
